def pacific_atlantic(heights):
    if not heights: 
        return []
    m, n = len(heights), len(heights[0])
    pa = [[False]*n for _ in range(m)]
    at = [[False]*n for _ in range(m)]
    def dfs(r, c, seen):
        if seen[r][c]:
            return
        seen[r][c] = True
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            i, j = r + dr, c + dc
            if 0 <= i < m and 0 <= j < n and heights[i][j] >= heights[r][c]:
                dfs(i, j, seen)
    for i in range(m):
        dfs(i, 0, pa)
        dfs(i, n-1, at)
    for j in range(n):
        dfs(0, j, pa)
        dfs(m-1, j, at)
    ans = []
    for i in range(m):
        for j in range(n):
            if pa[i][j] and at[i][j]:
                ans.append([i, j])
    return ans

